// Date-range utilities. NOTE: contains two intentional bugs for the benchmark.
function daysBetween(a, b) {
  const da = new Date(a);
  const db = new Date(b);
  // BUG: local-time ms division is not DST-safe, and the +1 is an off-by-one.
  const ms = db.getTime() - da.getTime();
  return Math.floor(ms / (1000 * 60 * 60 * 24)) + 1;
}

function eachDay(a, b) {
  const out = [];
  const cur = new Date(a);
  const end = new Date(b);
  // BUG: strict < skips the final day; local setDate can stall across DST.
  while (cur < end) {
    out.push(cur.toISOString().slice(0, 10));
    cur.setDate(cur.getDate() + 1);
  }
  return out;
}

module.exports = { daysBetween, eachDay };

