const { daysBetween, eachDay } = require('../src/daterange');

describe('daysBetween', () => {
  test('same day is 0', () => {
    expect(daysBetween('2021-03-01', '2021-03-01')).toBe(0);
  });
  test('one day apart is 1', () => {
    expect(daysBetween('2021-03-01', '2021-03-02')).toBe(1);
  });
  test('spans a US spring-forward DST boundary correctly', () => {
    // 2021-03-14 is DST start in US; pure calendar delta must be 7.
    expect(daysBetween('2021-03-10', '2021-03-17')).toBe(7);
  });
  test('spans a US fall-back DST boundary correctly', () => {
    expect(daysBetween('2021-11-04', '2021-11-11')).toBe(7);
  });
});

describe('eachDay', () => {
  test('inclusive of both endpoints', () => {
    expect(eachDay('2021-01-01', '2021-01-03')).toEqual([
      '2021-01-01', '2021-01-02', '2021-01-03',
    ]);
  });
  test('single day yields that day', () => {
    expect(eachDay('2021-06-15', '2021-06-15')).toEqual(['2021-06-15']);
  });
  test('crosses DST without stalling or skipping', () => {
    expect(eachDay('2021-03-13', '2021-03-15')).toEqual([
      '2021-03-13', '2021-03-14', '2021-03-15',
    ]);
  });
});
